var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"모두 대피하라! 숲의 신께서 진노하셨다……!","JPN":"皆退避しろ！　森の神がお怒りだ……！","ENG":"Evacuate, everyone! The lord of the forest is enraged...!","TWN":"全部撤退！森林之神發怒了……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L3_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"얌 카악스와 시선이 마주치면 안 된다! 진노한 신을 마주하는 자는……!","JPN":"ユム・カアシュと目を合わせてはならない！　怒りの神を目にした者は……！","ENG":"Do not meet Yum Kaax's gaze! Any who face the wrath of a god will...","TWN":"不能與姆卡許對視！面對已經憤怒的神明的人……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"히이익…! 주교님이 갑자기 토마토처럼 터져버렸어……!","JPN":"ひいい……！　主教様がトマトのように破裂した……！","ENG":"Eek...! The bishop just popped like a tomato...!","TWN":"咿……！主教突然像番茄一樣炸開了……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"아하하, 아하하하……! 어째서… 어째서야……!?","JPN":"あはは、あははは……！　なぜ……なぜだ……！？","ENG":"Ahaha, ahahahaha...! Why... why...?!","TWN":"啊哈哈，啊哈哈哈……！為什麼……為什麼啊……！？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"지금껏 산 제물을 그렇게나 많이 갖다 바쳤는데…!! 어째서……!!","JPN":"今まであんなにたくさんの生贄を捧げたのに……！！　なぜ……！！","ENG":"We've offered so many living sacrifices...! Just why...?!","TWN":"到現在為止已經獻上了那麼多活祭品……！！為什麼……！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그래서, 그 놈을 아십니까?","JPN":"で、あれが何か知っているんですか？","ENG":"So, do you know what that thing is?","TWN":"所以，你認識那傢伙嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"……얌 카악스라면.","JPN":"……ユム・カアシュは。","ENG":"...Yum Kaax is...","TWN":"……姆卡許。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"얌 카악스라면 천공섬 일대에 출몰했던 거대종 침식체예요.","JPN":"ユム・カアシュは天空島一帯に出没していた巨大種の侵食体です。","ENG":"\\"Yum Kaax is a colossal C.O. that appeared around the floating islands.\\"","TWN":"姆卡許是曾在天空島一帶出沒的巨型侵蝕體。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"매우 강력한 염동력을 쓰고, 그 신출귀몰한 움직임 때문에.","JPN":"非常に強力な念動力を使い、神出鬼没な動きをするので……","ENG":"\\"It wields powerful telekinesis and moves with uncanny speed.\\"","TWN":"他能使用非常強大的念力，並且神出鬼沒。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"측정된 침식파장에 비해, 그 위험도는 거의 5종 침식체 수준에 육박합니다.","JPN":"測定された侵食波長のわりに危険度は高く、ほぼ第5種侵食体と肩を並べるほどです。","ENG":"\\"Despite its measured Corruption ray, its threat level nearly rivals a Category 5 C.O.\\"","TWN":"相比於測量到的侵蝕波長，其危險度幾乎達到了5類侵蝕體的水準。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"단일 개체로서는 데몰리션 웜보다도 위험할지도 몰라요.","JPN":"単体としては、デモリッションワームより危険かもしれません。","ENG":"\\"As a single unit, it may even be more dangerous than a Demolition Worm.\\"","TWN":"作為個體，可能比爆破蠕蟲更危險。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시타 아가씨께서 우려를 표하십니다.","JPN":"……と、シータお嬢様は憂いでいらっしゃいます。","ENG":"...is what Lady Sita says with concern.","TWN":"……悉多小姐對此表示擔憂。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"5종 침식체 수준이라…….","JPN":"第5種侵食体か……","ENG":"A Category 5 C.O...","TWN":"……原來是5類侵蝕體。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하하, 이거 참~ 상황이 재미지게 돌아가네예.","JPN":"はは、まったく～面白いことになったな。","ENG":"Haha, this is turning into quite the show.","TWN":"哈哈，情況變得越來越有趣了呢。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"하지만 이상하네요.","JPN":"ですが、妙ですね。","ENG":"But it's strange.","TWN":"不過真奇怪。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"얌 카악스라면, 이미 캄파멘토 관리국 측에서 한 차례 토벌한 적이 있습니다.","JPN":"ユム・カアシュは過去に一度、カンパメント管理局により討伐されたことのある個体です。","ENG":"Yum Kaax was already subdued once by the Campamento Administration.","TWN":"姆卡許已經被坎帕門托管理局討伐過一次了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"캄파멘토 관리국을 필두로 담당 태스크포스들을 총동원한 결과…….","JPN":"カンパメント管理局を筆頭に、担当タスクフォースを総動員した結果……","ENG":"They mobilized all their TASKFORCEs, led by the Administration itself...","TWN":"以坎帕門托管理局為首，動員了所有負責的特遣勢力……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"공인 카운터 웨이드님께서 얌 카악스의 토벌에 성공하셨죠.","JPN":"公認カウンターウェイド様が、ユム・カアシュの討伐に成功しました。","ENG":"And Sir Wade, the Official Counter, succeeded in defeating it.","TWN":"公認制裁者韋德成功討伐了姆卡許。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"확실히… 그건 좀 수상하네예?","JPN":"確かに……それは変やな。","ENG":"True... That does sound suspicious.","TWN":"確實……那有點可疑吧？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"한 차례 토벌됐던 네임드 개체가 금방 또 나타나는 건, 말이 안 되는 기라.","JPN":"1度討伐されたネームド個体がすぐに再出現するなんて、ありえへん。","ENG":"A named C.O. taken down once shouldn't just pop right back up.","TWN":"曾經被討伐過的傢伙竟然再次出現，真是不可思議。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭐, 아무래도 그런 걸 고민할 시간은 없는 것 같네예.","JPN":"ま、でもそんなこと悩んでる暇はなさそうやな。","ENG":"Well, no time to dwell on that now.","TWN":"嗯，我們沒有時間去考慮這些事情了。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"두 번째 아티팩트는 이미 손에 넣었습니다. 그 놈이 오기 전에 서둘러야…….","JPN":"2つ目のアーティファクトはすでに入手済。あいつが来る前に急いで……","ENG":"We've already secured the second Artifact. We need to move before it gets here–","TWN":"第二個人造神器已經到手了。我們必須在那傢伙來之前趕緊……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"음? 이게 뭔소리고?","JPN":"ん？　何やこの音？","ENG":"Hmm? What's this?","TWN":"嗯？這是什麼聲音？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_MINI_MOVE_ATTACK"},{"id":"L39_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"커헉……!?","JPN":"がはっ……！？","ENG":"Gah...?!","TWN":"咳嚇……？！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG_02"},{"id":"L40_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미, 미리네 씨 괜찮으세요!","JPN":"マ、マリさん、大丈夫ですか！？","ENG":"Ms. Mi Rinae! Are you all right?!","TWN":"宓璃奈，你沒事吧！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"벌써 우리의 뒤를 쫓아오다니……!","JPN":"もう追ってくるなんて……！","ENG":"It's already caught up to us...!","TWN":"居然已經追上我們了……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L44_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 괘안타, 로빈아.","JPN":"平気、平気。","ENG":"Don't worry, Robin.","TWN":"沒事，蘿蘋。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"지금까지 지나온 수라장이 몇 개인데, 고작 요거 하나 가지고 우는 소리할 수는 없제.","JPN":"今まで何回修羅場をくぐって来たと思ってんねん。これぐらいで弱音吐いたらあかん。","ENG":"We've come through worse hellholes than this. No way I'm whining over just this.","TWN":"我們到目前為止經歷過那麼多慘況，怎麼能因為這點小事就哭哭啼啼的呢。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미리네 씨…….","JPN":"マリさん……","ENG":"Ms. Mi Rinae...","TWN":"宓璃奈……"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"참고로, 내는 사실 힘캐가 아니고 지능캐거든?","JPN":"ちなみにウチはな、力担当じゃなくて知能担当や。","ENG":"For the record, I'm not a power-build, but an intellect-build.","TWN":"順便說一下，其實我不是力量型角色，而是智力型角色喔。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"어떤 게임이든, 어떤 적이든… 결국엔 공략법이라는 게 있는 기라.","JPN":"どんなゲームでも、どんな敵でも……攻略法ってのがあるんや。","ENG":"Whatever the game, whatever the foe... there's always a strategy to beat it.","TWN":"無論是什麼遊戲，什麼敵人……最終都會有攻略的方法。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"조금만 버텨, 리네야.","JPN":"もう少し耐えてね、マリちゃん。","ENG":"Hang in there, Rinae.","TWN":"再堅持一下，宓璃奈。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_HATE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이쪽에서도 천공섬 지대와 침식체의 약점을 분석하고 있어!","JPN":"こっちも天空島一帯と侵食体の弱点を分析中よ！","ENG":"We're analyzing the floating island area and the C.O.'s weakness!","TWN":"這邊也在分析天空島地帶和侵蝕體的弱點！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"들었제? 이 싸움, 우리만 하는 게 아니다. 다들 도와주고 있다 아이가.","JPN":"聞いたやろ？　戦ってんのはウチらだけじゃない。みんな力を貸してくれてるんや。","ENG":"See? This fight isn't ours alone. Everyone's backing us up.","TWN":"聽到了吧？這場戰鬥，不只有我們，大家都在幫忙呢。"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"가면 카운터 알제? 모두가 한 마음이 되면… 지고 싶어도 질 수 없는 기다……!","JPN":"ほら、仮面カウンターもそうやろ？　みんなの心を一つにすれば……負けたくても負けられないんや……！","ENG":"You know the Masked Counter creed? When we stand as one... we can't lose, even if we tried...!","TWN":"你知道蒙面制裁者吧？當所有人心意相通時……即使想輸也輸不了……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"모두의 마음을 하나로……!","JPN":"みんなの心を一つに……！","ENG":"All hearts as one...!","TWN":"大家齊心協力……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"알겠습니다, 미리네 씨!","JPN":"分かりました、マリさん！","ENG":"Understood, Ms. Mi Rinae!","TWN":"明白了，宓璃奈！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AURA_ADMIN_NULL_NULL","text":{"KOREA":"그럼, 시간을 버는 건, 저와 오러 선생님에게 맡겨주세요……!","JPN":"じゃあ、時間稼ぎは私とオーラ先生に任せてください……！","ENG":"Then leave stalling for time to me and Ms. Aura...!","TWN":"那拖延時間的任務就交給我和奧蘿師父吧……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};